# =============================================================================\n# Library Management System - PowerShell Build & Run Script\n# =============================================================================\n# This script provides better error handling and Windows integration\n# compared to batch files.\n# =============================================================================\n\nparam(\n    [switch]$Clean,\n    [switch]$Verbose\n)\n\n# Set error action preference\n$ErrorActionPreference = \"Stop\"\n\n# Define project directory\n$ProjectDir = \"D:\\LMS_UPGRADE\\Library-managment-system-advanced-version\\Library\"\n\nWrite-Host \"`n===============================================\" -ForegroundColor Cyan\nWrite-Host \"   Library Management System - PowerShell\" -ForegroundColor Cyan\nWrite-Host \"===============================================`n\" -ForegroundColor Cyan\n\ntry {\n    # Change to project directory (correct PowerShell syntax)\n    if (-not (Test-Path $ProjectDir)) {\n        throw \"Project directory not found: $ProjectDir\"\n    }\n    \n    Set-Location -Path $ProjectDir\n    Write-Host \"[INFO] Working directory: $ProjectDir\" -ForegroundColor Green\n    \n    # Check Java installation\n    try {\n        $javaVersion = java -version 2>&1 | Select-String \"version\"\n        Write-Host \"[INFO] Java found: $($javaVersion.Line)\" -ForegroundColor Green\n    }\n    catch {\n        throw \"Java is not installed or not in PATH. Please install Java 17+ and add it to your PATH.\"\n    }\n    \n    # Clean previous build\n    Write-Host \"[1/4] Cleaning previous build...\" -ForegroundColor Yellow\n    if (Test-Path \"target\") {\n        Remove-Item -Path \"target\" -Recurse -Force\n        Write-Host \"  ✓ Previous build cleaned\" -ForegroundColor Green\n    }\n    New-Item -ItemType Directory -Path \"target\\classes\" -Force | Out-Null\n    \n    # Compile Java files\n    Write-Host \"[2/4] Compiling Java source files...\" -ForegroundColor Yellow\n    \n    $sourceFiles = @(\n        \"src\\main\\java\\com\\library\\*.java\",\n        \"src\\main\\java\\com\\library\\model\\*.java\",\n        \"src\\main\\java\\com\\library\\repository\\*.java\",\n        \"src\\main\\java\\com\\library\\service\\*.java\",\n        \"src\\main\\java\\com\\library\\util\\*.java\",\n        \"src\\main\\java\\com\\library\\controller\\*.java\",\n        \"src\\main\\java\\com\\library\\ui\\*.java\"\n    )\n    \n    $compileArgs = @(\n        \"-cp\", \"lib\\*\",\n        \"-d\", \"target\\classes\"\n    ) + $sourceFiles\n    \n    $compileProcess = Start-Process -FilePath \"javac\" -ArgumentList $compileArgs -Wait -PassThru -NoNewWindow\n    \n    if ($compileProcess.ExitCode -ne 0) {\n        throw \"Compilation failed with exit code: $($compileProcess.ExitCode)\"\n    }\n    \n    Write-Host \"  ✓ Compilation successful\" -ForegroundColor Green\n    \n    # Copy resources\n    Write-Host \"[3/4] Copying resources...\" -ForegroundColor Yellow\n    if (Test-Path \"src\\main\\resources\") {\n        Copy-Item -Path \"src\\main\\resources\\*\" -Destination \"target\\classes\\\" -Recurse -Force\n        Write-Host \"  ✓ Resources copied successfully\" -ForegroundColor Green\n    } else {\n        Write-Host \"  ! Resources directory not found\" -ForegroundColor Yellow\n    }\n    \n    # Verify main class exists\n    $mainClassPath = \"target\\classes\\com\\library\\ProfessionalLibraryApp.class\"\n    if (-not (Test-Path $mainClassPath)) {\n        throw \"Main class not found after compilation: $mainClassPath\"\n    }\n    \n    # Start application\n    Write-Host \"[4/4] Starting Library Management System...\" -ForegroundColor Yellow\n    Write-Host \"`n===============================================\" -ForegroundColor Cyan\n    Write-Host \"   Application is starting...\" -ForegroundColor Cyan\n    Write-Host \"   Login credentials: admin / admin\" -ForegroundColor Cyan\n    Write-Host \"===============================================`n\" -ForegroundColor Cyan\n    \n    # Run with native access enabled for SQLite (fixes the warning)\n    $javaArgs = @(\n        \"--enable-native-access=ALL-UNNAMED\",\n        \"-cp\", \"lib\\*;target\\classes\",\n        \"com.library.ProfessionalLibraryApp\"\n    )\n    \n    $appProcess = Start-Process -FilePath \"java\" -ArgumentList $javaArgs -Wait -PassThru -NoNewWindow\n    \n    Write-Host \"`n===============================================\" -ForegroundColor Cyan\n    if ($appProcess.ExitCode -eq 0) {\n        Write-Host \"   Application closed normally\" -ForegroundColor Green\n    } else {\n        Write-Host \"   Application exited with error code: $($appProcess.ExitCode)\" -ForegroundColor Red\n    }\n    Write-Host \"===============================================`n\" -ForegroundColor Cyan\n    \n}\ncatch {\n    Write-Host \"`n[ERROR] $($_.Exception.Message)\" -ForegroundColor Red\n    Write-Host \"===============================================`n\" -ForegroundColor Red\n    exit 1\n}\n\nWrite-Host \"Press any key to exit...\"\n$null = $Host.UI.RawUI.ReadKey(\"NoEcho,IncludeKeyDown\")